def get_band_milestones(band_name):
    milestones = {
        "Band": band_name,
        "Established": 1978,
        "Biggest Album": {"Title": "Hier en nu", "Year": 1990, "Sales": "100,000 copies"},
        "Highest-Selling Single": {"Title": "Ik Wil Je", "Sales": "1 million+ copies"}
    }
    return milestones

# Example usage:
print(get_band_milestones("De Kreuners"))

This function returns a structured dictionary with key details about the band's milestones.
